const chatInput = $('Pre-Procesing3').first().json.chatInput.trim();
const sessionId = $('Pre-Procesing3').first().json.sessionId;
const adminPassword = $('Admin Password').first().json.adminPassword;

// Detect command type
const aprender      = chatInput.match(/^\/aprender\s+(\S+)\s+(\S+)\s*:\s*(.+)$/si);
const listar        = /^\/listar-aprendizajes/i.test(chatInput);
const borrar        = chatInput.match(/^\/borrar-aprendizaje\s+(\d+)\s+(\S+)/i);

let commandType = 'NONE';
let payload = {};

if (aprender) {
  const parts = chatInput.match(/^\/aprender\s+(\S+)\s+(\S+)\s*:\s*(.+)$/si);
  commandType = 'APRENDER';
  payload = {
    password:    parts[1].trim(),
    categoria:   parts[2].trim().toUpperCase(),
    instruccion: parts[3].trim()
  };
} else if (listar) {
  const parts = chatInput.match(/^\/listar-aprendizajes\s*(\S+)?/i);
  commandType = 'LISTAR';
  payload = { password: parts && parts[1] ? parts[1].trim() : '' };
} else if (borrar) {
  commandType = 'BORRAR';
  payload = {
    id:       parseInt(borrar[1]),
    password: borrar[2].trim()
  };
}

return [{
  json: {
    chatInput,
    sessionId,
    adminPassword,
    commandType,
    payload,
    isCommand: commandType !== 'NONE'
  }
}];

return [{ json: {
  output: '<div style="font-family:sans-serif;padding:14px 18px;border-left:4px solid #e53e3e;border-radius:6px;background:#fff5f5;font-size:14px;color:#333">'
        + '<strong>&#128274; Clave incorrecta</strong><br>'
        + '<span style="font-size:13px;color:#666">El comando no fue ejecutado.</span>'
        + '</div>',
  type: 'conversation'
}}];

const id = ($input.first().json.id || $input.first().json[0]?.id || '?');
const categoria = $('Detect Command').first().json.payload.categoria;
const instruccion = $('Detect Command').first().json.payload.instruccion;

return [{ json: {
  output: '<div style="font-family:sans-serif;padding:14px 18px;border-left:4px solid #faa819;border-radius:6px;background:#fff8ee;font-size:14px;color:#333">'
        + '<strong>&#9989; Aprendizaje guardado</strong> <span style="font-size:12px;color:#888">#' + id + '</span><br><br>'
        + '<span style="font-size:12px;background:#faa81920;border-radius:4px;padding:2px 8px;color:#7a5800">' + categoria + '</span><br><br>'
        + '<span style="color:#444">' + instruccion + '</span>'
        + '</div>',
  type: 'conversation'
}}];

const rows = $input.all().map(i => i.json);
const GOLD = '#faa819';

if (rows.length === 0 || (rows.length === 1 && Object.keys(rows[0]).length === 0)) {
  return [{ json: {
    output: '<div style="font-family:sans-serif;padding:14px 18px;border-left:4px solid #faa819;border-radius:6px;background:#fff8ee;font-size:14px;color:#333">'
          + '&#128218; No hay aprendizajes guardados aún.</div>',
    type: 'conversation'
  }}];
}

let items = '';
rows.forEach(function(r) {
  const fecha = r.creado_en ? new Date(r.creado_en).toLocaleDateString('es-VE') : '';
  items += '<div style="padding:10px 12px;border:0.5px solid #e8e8e8;border-radius:6px;margin-bottom:6px;background:#fff">'
         + '<div style="display:flex;align-items:center;gap:8px;margin-bottom:4px">'
         + '<span style="font-size:11px;font-weight:600;background:#faa81920;color:#7a5800;padding:2px 8px;border-radius:20px">' + r.categoria + '</span>'
         + '<span style="font-size:11px;color:#aaa;margin-left:auto">#' + r.id + ' · ' + fecha + '</span>'
         + '</div>'
         + '<div style="font-size:13px;color:#444">' + r.instruccion + '</div>'
         + '<div style="font-size:11px;color:#aaa;margin-top:4px">Para borrar: /borrar-aprendizaje ' + r.id + ' [clave]</div>'
         + '</div>';
});

return [{ json: {
  output: '<div style="font-family:sans-serif;max-width:680px">'
        + '<div style="padding:10px 14px;background:#fff8ee;border-left:4px solid ' + GOLD + ';border-radius:6px;margin-bottom:12px;font-size:13px;color:#333">'
        + '&#128218; <strong>' + rows.length + '</strong> aprendizaje(s) activo(s):</div>'
        + items + '</div>',
  type: 'conversation'
}}];

const id = $('Detect Command').first().json.payload.id;
return [{ json: {
  output: '<div style="font-family:sans-serif;padding:14px 18px;border-left:4px solid #faa819;border-radius:6px;background:#fff8ee;font-size:14px;color:#333">'
        + '&#128465; Aprendizaje <strong>#' + id + '</strong> desactivado correctamente.'
        + '</div>',
  type: 'conversation'
}}];

const body = $input.item.json.body || {};
const chatInput = body.chatInput || body.message || '';
const sessionId = body.sessionId || body.session_id || 'no-session-id';
return { json: { chatInput, sessionId } };

const rawOutput = $input.item.json.output || '';

let cleaned = rawOutput
  .replace(/```(?:json)?\s*/gi, '')
  .replace(/```\s*/g, '')
  .trim();

cleaned = cleaned.replace(/"([^"\\]*(?:\\.[^"\\]*)*)"\s*:/g, (match, key) => {
  const cleanKey = key.replace(/[\n\r]/g, '');
  return '"' + cleanKey + '":';
});

const braceStart = cleaned.indexOf('{');
const braceEnd = cleaned.lastIndexOf('}');
let parsed = null;

if (braceStart !== -1 && braceEnd > braceStart) {
  const jsonCandidate = cleaned.substring(braceStart, braceEnd + 1);
  try {
    parsed = JSON.parse(jsonCandidate);
  } catch(e) {
    const extract = (key) => {
      const r = new RegExp('"' + key + '"\\s*:\\s*"([^"]+)"', 'i');
      const m = jsonCandidate.match(r);
      return m ? m[1].replace(/[\n\r]/g, '').trim() : null;
    };
    const extractBool = (key) => {
      const r = new RegExp('"' + key + '"\\s*:\\s*(true|false)', 'i');
      const m = jsonCandidate.match(r);
      return m ? m[1].toLowerCase() === 'true' : false;
    };
    const whereClause = extract('whereClause');
    if (whereClause) {
      parsed = {
        whereClause,
        queryIntent: extract('queryIntent') || 'SERVICE',
        isSearchReady: extractBool('isSearchReady'),
        humanSummary: extract('humanSummary') || 'Búsqueda de empresas'
      };
    }
  }
}

const isReady = parsed &&
  parsed.whereClause &&
  typeof parsed.whereClause === 'string' &&
  parsed.whereClause.trim().length > 0 &&
  (parsed.isSearchReady === true || parsed.isSearchReady === 'true');

if (isReady) {
  let safeWhere = parsed.whereClause.replace(/[\n\r]/g, ' ').trim();
  safeWhere = safeWhere.replace(
    /\b(Sector|Servicios)\s*=\s*'([^']+)'/gi,
    (match, col, val) => `LOWER(${col}) LIKE LOWER('%${val}%')`
  );
  safeWhere = safeWhere.replace(
    /\b(Sector|Servicios)\s*=\s*"([^"]+)"/gi,
    (match, col, val) => `LOWER(${col}) LIKE LOWER('%${val}%')`
  );
  return {
    json: {
      isSearchReady: 'true',
      needsClarification: 'false',
      whereClause: safeWhere,
      queryIntent: (parsed.queryIntent || 'SERVICE').replace(/[\n\r]/g, '').trim(),
      humanSummary: (parsed.humanSummary || 'Búsqueda de empresas').replace(/[\n\r]/g, '').trim()
    }
  };
}

const conversationalText = cleaned.replace(/\{[\s\S]*\}/, '').trim() || cleaned;
return {
  json: {
    isSearchReady: 'false',
    needsClarification: 'true',
    whereClause: null,
    queryIntent: 'UNKNOWN',
    humanSummary: null,
    conversationalText: conversationalText || rawOutput.trim()
  }
};

const rows      = $input.all().map(i => i.json);
const parseNode = $('Parse Intent JSON3').first().json;
const summary   = parseNode.humanSummary || 'Búsqueda de empresas';
const intent    = (parseNode.queryIntent || 'MIXED').toUpperCase();
const count     = rows.length;

const GOLD   = '#faa819';
const GOLDSM = '#faa81920';
const DARK   = 'var(--color-text-primary)';
const TEXT   = 'var(--color-text-secondary)';
const BG     = 'var(--color-background-primary)';
const BGALT  = 'var(--color-background-secondary)';
const BORDER = 'var(--color-border-tertiary)';

function norm(r) {
  var raw = String(r.website || r.WEBSITE || '').trim();
  var web = raw ? (/^https?:\/\//i.test(raw) ? raw : 'https://' + raw) : '';
  return {
    name:      r.name      || r.NAME      || 'Sin nombre',
    rif:       r.rif       || r.RIF       || '',
    sector:    r.Sector    || r.SECTOR    || '',
    servicios: r.Servicios || r.SERVICIOS || '',
    ciudad:    r.CIUDAD    || r.ciudad    || '',
    estado:    r.state     || r.STATE     || '',
    phone:     r.phone     || r.PHONE     || '',
    street:    r.street    || r.STREET    || '',
    website:   web
  };
}

function chip(icon, text) {
  if (!text) return '';
  return '<span style="display:inline-flex;align-items:center;gap:4px;background:' + BGALT + ';border-radius:20px;padding:3px 10px;font-size:12px;color:' + TEXT + ';margin:2px 2px 0 0">' + icon + ' ' + text + '</span>';
}
function pill(text, bg, color) {
  if (!text) return '';
  return '<span style="display:inline-block;background:' + bg + ';border-radius:20px;padding:2px 10px;font-size:11px;color:' + color + ';font-weight:500;margin:2px 2px 0 0">' + text + '</span>';
}
function sectorPills(str) {
  if (!str) return '';
  return str.split(',').map(function(s) { return pill(s.trim(), GOLDSM, '#7a5800'); }).join('');
}
function serviciosPills(str) {
  if (!str) return '';
  return str.split(',').map(function(s) { return pill(s.trim(), 'var(--color-background-info)', 'var(--color-text-info)'); }).join('');
}

function cardFull(c) {
  var rif   = c.rif    ? chip('&#128196;', 'RIF: ' + c.rif) : '';
  var tel   = c.phone  ? chip('&#128222;', c.phone) : '';
  var loc   = c.ciudad ? chip('&#127748;', c.ciudad + (c.estado ? ', ' + c.estado : '')) : '';
  var addr  = c.street ? '<div style="font-size:12px;color:' + TEXT + ';margin-top:6px">&#128205; ' + c.street + '</div>' : '';
  var wlink = '';
  if (c.website) {
    var lbl = c.website.replace(/^https?:\/\//i,'').replace(/\/$/,'');
    wlink = '<div style="margin-top:6px"><a href="' + c.website + '" target="_blank" rel="noopener" style="color:' + GOLD + ';text-decoration:none;font-size:12px">&#127760; ' + lbl + '</a></div>';
  }
  return '<div style="border-left:4px solid ' + GOLD + ';padding:14px 16px;border-radius:0 var(--border-radius-lg) var(--border-radius-lg) 0;background:' + BG + ';border:0.5px solid ' + BORDER + ';border-left:4px solid ' + GOLD + '"><div style="font-weight:500;font-size:15px;color:' + DARK + ';margin-bottom:8px">&#127970; ' + c.name + '</div>' + (c.sector ? '<div style="margin-bottom:5px">' + sectorPills(c.sector) + '</div>' : '') + (c.servicios ? '<div style="margin-bottom:5px">' + serviciosPills(c.servicios) + '</div>' : '') + '<div style="margin-top:6px">' + loc + tel + rif + '</div>' + addr + wlink + '</div>';
}

function listRow(c, idx) {
  var safeNameJs = c.name.replace(/'/g, "\\'").replace(/"/g, '&quot;');
  var onclick = "sendPrompt('dame información sobre la empresa " + safeNameJs + "')";
  return '<div onclick="' + onclick + '" style="display:flex;align-items:center;gap:12px;padding:10px 14px;background:' + BG + ';border:0.5px solid ' + BORDER + ';border-radius:var(--border-radius-md);cursor:pointer;transition:background 0.15s" onmouseover="this.style.background=\'var(--color-background-secondary)\';this.style.borderColor=\'#faa819\'" onmouseout="this.style.background=\'var(--color-background-primary)\';this.style.borderColor=\'var(--color-border-tertiary)\'">' + '<span style="font-size:12px;color:' + TEXT + ';min-width:20px;text-align:right">' + (idx+1) + '</span>' + '<span style="flex:1;font-size:14px;color:' + DARK + ';font-weight:500">&#127970; ' + c.name + '</span>' + '<span style="font-size:12px;color:' + GOLD + ';font-weight:500">ver detalle &#8250;</span>' + '</div>';
}

function header(html) {
  return '<div style="margin-bottom:12px;font-size:13px;color:' + TEXT + ';padding:10px 14px;background:' + BGALT + ';border-radius:var(--border-radius-md)">' + html + '</div>';
}

var output = '';
var companies  = rows.map(norm);
var isFullCard = (intent === 'COMPANY' || intent === 'RIF');

if (isFullCard) {
  var headerHtml = '&#128269; Encontré <strong>' + count + '</strong> empresa(s) cuyo nombre se aproxima a <strong>"' + summary + '"</strong>. ¿Te refieres a alguna de estas?';
  var cardsHtml  = companies.map(cardFull).join('<div style="height:8px"></div>');
  output = '<div style="font-family:var(--font-sans);max-width:680px">' + header(headerHtml) + cardsHtml + '</div>';
} else {
  var hint = count >= 10 ? ' <span style="font-size:11px;color:' + TEXT + '">(mostrando los primeros ' + count + ')</span>' : '';
  var headerHtml = '&#9989; Encontré <strong>' + count + '</strong> empresa(s) para <em>' + summary + '</em>' + hint + '.<br><span style="font-size:12px;color:' + TEXT + '">Haz clic en una empresa para ver su información completa.</span>';
  var rowsHtml = companies.map(listRow).join('');
  output = '<div style="font-family:var(--font-sans);max-width:680px">' + header(headerHtml) + '<div style="display:flex;flex-direction:column;gap:6px">' + rowsHtml + '</div></div>';
}

return [{ json: { output } }];
